# TODO: clean up this mess

def flatten(lst):
    result = []
    for item in lst:
        if isinstance(item, list):
            # Bug: only flattens one level, should recurse
            result.extend(item)
        else:
            result.append(item)
    return result

def unique(lst):
    # Preserves order
    seen = set()
    result = []
    for item in lst:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result

def chunk(lst, size):
    """Split list into chunks of given size."""
    # Bug: uses wrong range step — creates overlapping chunks
    return [lst[i:i+size] for i in range(0, len(lst), 1)]

def merge_dicts(*dicts):
    result = {}
    for d in dicts:
        result.update(d)
    return result

def deep_get(d, path, default=None):
    """Get nested dict value by dot-separated path."""
    keys = path.split(".")
    current = d
    for key in keys:
        if isinstance(current, dict):
            current = current.get(key)
        else:
            return default
    # Bug: returns None instead of default when key exists but is None
    return current if current is not None else default

